class Solution:
    def powerfulIntegers(self, x: int, y: int, bound: int) -> List[int]:
        x_pows = set()
        current = 1
        x_pows.add(current)
        if x != 1:
            while True:
                next_val = current * x
                if next_val > bound:
                    break
                current = next_val
                x_pows.add(current)

        y_pows = set()
        current = 1
        y_pows.add(current)
        if y != 1:
            while True:
                next_val = current * y
                if next_val > bound:
                    break
                current = next_val
                y_pows.add(current)

        result = set()
        for a in x_pows:
            for b in y_pows:
                s = a + b
                if s <= bound:
                    result.add(s)
        return sorted(result)

